iv = bytes.fromhex("088b0de44fb2522ac672356670bf8d00")
ciphertext = bytes.fromhex("0397a2401cbbf6d966d0023207c31bc14c36d1609a1ee615f5e694e98ed10999bb38f8e72a27a790061a41ca550f91c9")

def evaluate_gate(Wa, Wb, gate):
    Wc = [None] * 2

    for a in [0, 1]:
        for b in [0, 1]:
            La, pa = Wa[a]
            Lb, pb = Wb[b]
            ct, pc = gate[2 * a + b]

            if Wc[pc] is not None:
              continue

            Lc = xor(ct, H(La, Lb))
            Wc[pc] = (Lc, pc)

    return Wc

def generate_secret(wires, gates):
    secret = b""
    intermediate_wires = []

    for x in range(4):
        for y in range(4):
            gate = gates[4 * x + y]
            intermediate_wires.append(evaluate_gate(wires[y], wires[(y+1) % 4], gate))

        for y in range(4):
            Lc, pc = intermediate_wires[4 * x + y][1]
            secret += Lc[-1:]
            wires[y] = intermediate_wires[4 * x + y]

    return secret

def main():
    secret = generate_secret(wires, gates)

    cipher = AES.new(secret, AES.MODE_CBC, iv)
    flag = cipher.decrypt(ciphertext)

    print(flag)

if __name__ == "__main__":
    main()